      "content": "const { randomUUID } = require('node:crypto');

let tasksStore = {};

function createTask(projectId, taskData) {
  const taskId = randomUUID();
  if (!tasksStore[projectId]) {
    tasksStore[projectId] = {};
  }
  tasksStore[projectId][taskId] = { ...taskData, id: taskId, status: 'todo' };
  return tasksStore[projectId][taskId];
}

function getTasks(projectId, status) {
  const tasks = tasksStore[projectId] ? Object.values(tasksStore[projectId]) : [];
  if (status) {
    return tasks.filter(task => task.status === status);
  }
  return tasks;
}

function updateTask(projectId, taskId, updatedData) {
  if (!tasksStore[projectId] || !tasksStore[projectId][taskId]) {
    return null;
  }
  const task = tasksStore[projectId][taskId];
  if (updatedData.status && ['todo', 'done'].includes(updatedData.status)) {
    task.status = updatedData.status;
  }
  return task;
}

module.exports = { createTask, getTasks, updateTask };
